// ── Monthly price map (for calculating differences, tier gate logic) ─────────

export const TIER_MONTHLY_MAP = Object.fromEntries(
  Object.entries(AURA_TIERS).map(([k, v]) => [k, v.price])
);
// Also alias 'free' → 0 for backward compat
TIER_MONTHLY_MAP.free = 0;

// ── Formatted price strings ──────────────────────────────────────────────────

export function tierPrice(tierKey) {
  const t = AURA_TIERS[tierKey];
  if (!t) return '$0/mo';
  if (t.price === 0) return 'Free';
  return `$${t.price}/mo`;
}

export function tierAnnualPrice(tierKey) {
  const t = AURA_TIERS[tierKey];
  if (!t || t.annualPrice === 0) return 'Free';
  return `$${t.annualPrice.toLocaleString()}/yr`;
}

